    matched, excgroup = excgroup.split(exc_types)
    if matched:
        try:
            result = handler(matched)
            # Check if handler returned a coroutine (likely from async function)
            if result is not None and inspect.iscoroutine(result):
                raise TypeError(
                    f"Error trying to handle {matched!r} with {handler!r}. "
                    f"Exception handler must be a sync function."
                )
        except BaseException as new_exc:
            new_exceptions.append(new_exc)

